            page_ptr_1g_lemma();
        };
        assert(self.allocated_pages_4k_wf());
        assert(self.allocated_pages_2m_wf()) by {
            page_ptr_2m_lemma();
        };
        assert(self.allocated_pages_1g_wf()) by {
            page_ptr_1g_lemma();
        };
        assert(self.mapped_pages_4k_wf());
        assert(self.mapped_pages_2m_wf()) by {
            page_ptr_2m_lemma();
